[CmdletBinding(SupportsShouldProcess=$true)]
param([Parameter(Mandatory)][ValidatePattern('^[A-Z]:$')][string]$MountPoint,[switch]$ResumeProtection,[switch]$EnableProtection,[switch]$AddRecoveryPassword,[switch]$BackupRecoveryKeyToAD,[string]$OutputPath="$env:USERPROFILE\Desktop\BitLockerRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($ResumeProtection-or$EnableProtection-or$AddRecoveryPassword-or$BackupRecoveryKeyToAD)){throw'Choose at least one repair action.'};$v=Get-BitLockerVolume -MountPoint $MountPoint -ErrorAction Stop;$v|Export-Clixml (Join-Path $OutputPath 'before.xml')
if($ResumeProtection-and$PSCmdlet.ShouldProcess($MountPoint,'Resume BitLocker protection')){Resume-BitLocker -MountPoint $MountPoint;L'Protection resumed.'}
if($AddRecoveryPassword-and$PSCmdlet.ShouldProcess($MountPoint,'Add recovery password protector')){Add-BitLockerKeyProtector -MountPoint $MountPoint -RecoveryPasswordProtector|Out-Null;L'Recovery password protector added.'}
if($EnableProtection-and$PSCmdlet.ShouldProcess($MountPoint,'Enable BitLocker encryption')){if($v.VolumeStatus-eq'FullyDecrypted'){Enable-BitLocker -MountPoint $MountPoint -UsedSpaceOnly -RecoveryPasswordProtector -EncryptionMethod XtsAes256 -SkipHardwareTest}else{Resume-BitLocker -MountPoint $MountPoint};L'BitLocker enablement requested.'}
if($BackupRecoveryKeyToAD){$vol=Get-BitLockerVolume -MountPoint $MountPoint;$ids=$vol.KeyProtector|Where-Object KeyProtectorType-eq'RecoveryPassword'|Select-Object -Expand KeyProtectorId;if(-not$ids){throw'No recovery password protector found.'};foreach($id in $ids){if($PSCmdlet.ShouldProcess($id,'Back up recovery password to Active Directory')){Backup-BitLockerKeyProtector -MountPoint $MountPoint -KeyProtectorId $id;L"Backed up $id"}}}
Get-BitLockerVolume -MountPoint $MountPoint|Export-Clixml (Join-Path $OutputPath 'after.xml');L'Repair workflow finished.'